		defaultName: "bragi",
	}
	svc := newTestService(t, ServiceOptions{ServiceConfig: sc})

	models, err := svc.ListModels(context.Background(), ModelFilter{})
	if err != nil {
		t.Fatalf("ListModels: %v", err)
	}
	if len(models) != 2 {
		t.Fatalf("ListModels rows = %d, want 2 (rows=%#v)", len(models), models)
	}
	wantRows := make(map[string]ModelInfo, len(models))
	for _, model := range models {
		key := model.Provider + "\x00" + model.ID + "\x00" + model.EndpointName + "\x00" + model.ServerInstance
		wantRows[key] = model
	}

	if err := svc.RecordRouteAttempt(context.Background(), RouteAttempt{
		Provider:  "bragi@primary",
		Endpoint:  "primary",
		Model:     "qwen3.5-27b",
		Status:    "failed",
		Reason:    "route_attempt_failure",
		Timestamp: time.Now().Add(-time.Second),
	}); err != nil {
		t.Fatalf("RecordRouteAttempt: %v", err)
	}

	report, err := svc.RouteStatus(context.Background())
	if err != nil {
		t.Fatalf("RouteStatus: %v", err)
	}
	if len(report.Routes) != 1 {
		t.Fatalf("Routes: got %d, want 1", len(report.Routes))
	}

	entry := report.Routes[0]
	if entry.Model != "qwen3.5-27b" {
		t.Errorf("Model: got %q, want %q", entry.Model, "qwen3.5-27b")
	}
	if entry.Strategy != "auto" {
		t.Errorf("Strategy: got %q, want auto", entry.Strategy)
	}
	if len(entry.Candidates) != 2 {
		t.Fatalf("Candidates: got %d, want 2", len(entry.Candidates))
	}

	byEndpoint := make(map[string]RouteCandidateStatus, len(entry.Candidates))
	for _, c := range entry.Candidates {
		byEndpoint[c.Endpoint] = c
		key := c.Provider + "\x00" + c.Model + "\x00" + c.Endpoint + "\x00" + c.ServerInstance
		if _, ok := wantRows[key]; !ok {
			t.Fatalf("RouteStatus candidate %q does not match a list-models row; candidates=%#v rows=%#v", key, entry.Candidates, models)
		}
		if c.Provider != "bragi" {
			t.Errorf("candidate provider = %q, want bragi", c.Provider)
		}
		if c.Billing != BillingModelFixed {
			t.Errorf("candidate billing = %q, want fixed", c.Billing)
		}
		if c.Model != "qwen3.5-27b" {
			t.Errorf("candidate model = %q, want qwen3.5-27b", c.Model)
		}
		if c.ServerInstance == "" {
			t.Errorf("candidate server_instance should be populated: %#v", c)
		}
	}

	primary := byEndpoint["primary"]
	if primary.Cooldown == nil {
		t.Fatalf("primary endpoint should be in cooldown: %#v", primary)
	}
	if primary.Healthy {
		t.Fatalf("primary endpoint should not be healthy while in cooldown: %#v", primary)
	}
	backup := byEndpoint["backup"]
	if backup.Cooldown != nil {
		t.Fatalf("backup endpoint should not be in cooldown: %#v", backup)
	}
	if !backup.Healthy {
		t.Fatalf("backup endpoint should remain healthy: %#v", backup)
	}
}

// TestRouteStatusLastDecisionCached verifies that calling ResolveRoute and
// then RouteStatus surfaces the cached LastDecision on the matching entry.
func TestRouteStatusLastDecisionCached(t *testing.T) {
	isolateRouteStatusTestEnv(t)
	// Build a minimal ServiceConfig that satisfies the routing engine.
	sc := &fakeServiceConfig{
		providers: map[string]ServiceProviderEntry{
			"bragi": {Type: "lmstudio", BaseURL: "http://127.0.0.1:9999/v1", Model: "qwen3-27b"},
		},
		names:       []string{"bragi"},
		defaultName: "bragi",
	}

	// Seed registry with the "fiz" harness available so routing can resolve.
	reg := harnesses.NewRegistry()
	svc := &service{
		opts:     ServiceOptions{ServiceConfig: sc},
		registry: reg,
	}

	// Inject a decision directly into the cache (simulating a resolved route)
	// since ResolveRoute may fail without a real provider.
	dec := &RouteDecision{
		Harness:        "fiz",
		Provider:       "bragi",
		Endpoint:       "desk-a",
		ServerInstance: "desk-a",
		Model:          "qwen3-27b",
		Reason:         "test",
		Sticky:         RouteStickyState{KeyPresent: true, Assignment: "reused", ServerInstance: "desk-a", Reason: "live sticky lease reused"},
	}
	svc.cacheRouteDecision("qwen3-27b", dec)

	report, err := svc.RouteStatus(context.Background())
	if err != nil {
		t.Fatalf("RouteStatus: %v", err)
	}
	if len(report.Routes) != 1 {
		t.Fatalf("Routes: got %d, want 1", len(report.Routes))
	}
	entry := report.Routes[0]
	if entry.LastDecision == nil {
		t.Fatal("LastDecision: expected non-nil after ResolveRoute")
	}
	if entry.LastDecision.Provider != "bragi" {
		t.Errorf("LastDecision.Provider: got %q, want %q", entry.LastDecision.Provider, "bragi")
	}
	if entry.LastDecision.ServerInstance == "" {
		t.Errorf("LastDecision.ServerInstance should be populated: %#v", entry.LastDecision)
	}
	if entry.LastDecision.Model != "qwen3-27b" {
		t.Errorf("LastDecision.Model: got %q, want %q", entry.LastDecision.Model, "qwen3-27b")
	}
	if entry.LastDecisionAt.IsZero() {
		t.Error("LastDecisionAt: should be non-zero")
	}
	if entry.SelectedEndpoint != "desk-a" {
		t.Fatalf("SelectedEndpoint = %q, want desk-a", entry.SelectedEndpoint)
	}
	if entry.SelectedServerInstance == "" {
		t.Fatalf("SelectedServerInstance should be populated: %#v", entry)
	}
	if !entry.Sticky.KeyPresent || entry.Sticky.Assignment != "reused" {
		t.Fatalf("Sticky = %#v, want reused sticky evidence", entry.Sticky)
	}
}

// TestRouteStatusLastDecisionCachedViaResolveRoute verifies the full path:
// ResolveRoute → cache write → RouteStatus reads cache.
func TestRouteStatusLastDecisionCachedViaResolveRoute(t *testing.T) {
	isolateRouteStatusTestEnv(t)
	// We need the routing engine to actually resolve. The engine picks
	// harnesses from the registry. "fiz" is always in the registry.
	// We give it a provider so the engine can build a candidate.
	sc := &fakeServiceConfig{
		providers: map[string]ServiceProviderEntry{
			"bragi": {Type: "lmstudio", BaseURL: "http://127.0.0.1:9999/v1", ServerInstance: "bragi-instance", Model: "mymodel"},
		},
		names:       []string{"bragi"},
		defaultName: "bragi",
	}

	svc := &service{
		opts:     ServiceOptions{ServiceConfig: sc},
		registry: harnesses.NewRegistry(),
	}

	// ResolveRoute with model="mymodel". The engine resolves against the
	// "fiz" harness + bragi provider.
	dec, err := svc.ResolveRoute(context.Background(), RouteRequest{
		Model:    "mymodel",
		Provider: "bragi",
	})
	if err != nil {
		// Routing may return an error if the engine can't fully resolve;
		// skip in that case — the direct-cache test covers the cache logic.
		t.Skipf("ResolveRoute returned error (provider not live): %v", err)
	}
	if dec == nil {
		t.Fatal("RouteDecision: nil")
	}

	report, err := svc.RouteStatus(context.Background())
	if err != nil {
		t.Fatalf("RouteStatus: %v", err)

	ActualCashSpend bool
	// Endpoint is the provider endpoint name when applicable.
	Endpoint string
	// ServerInstance is the normalized server identity for the candidate.
	ServerInstance string
	// Model is the candidate concrete model.
	Model string
	// Score is the routing score assigned before final ordering.
	Score float64
	// CostUSDPer1kTokens is the estimated blended USD cost per 1,000 tokens.
	CostUSDPer1kTokens float64
	// CostSource indicates whether cost came from catalog, subscription,
	// user-config, or is unknown.
	CostSource string
	// EffectiveCost is the score-time cost estimate surfaced explicitly for
	// operator traces and session logs.
	EffectiveCost float64
	// EffectiveCostSource records where EffectiveCost came from.
	EffectiveCostSource string
	// Eligible reports whether the candidate passed all routing gates.
	Eligible bool
	// Reason is the scoring reason for eligible candidates or the rejection
	// reason for ineligible candidates.
	Reason string
	// FilterReason names the gate that disqualified an ineligible candidate.
	// Empty when Eligible. See the FilterReason* constants.
	FilterReason string
	// ContextLength is the resolved maximum context window for the candidate.
	ContextLength int
	// ContextSource records where ContextLength came from.
	ContextSource string
	// SourceStatus records the model snapshot status for this candidate.
	SourceStatus string
	// AutoRoutable reports whether the snapshot/catalog marks the candidate as
	// eligible for automatic routing.
	AutoRoutable bool
	// ExactPinOnly reports whether the candidate is only eligible when pinned
	// explicitly.
	ExactPinOnly bool
	// ExclusionReason explains why the snapshot marked the candidate as
	// excluded from automatic routing.
	ExclusionReason string
	// SnapshotCapturedAt records when the model snapshot used for scoring
	// was assembled.
	SnapshotCapturedAt time.Time
	// HealthFreshnessAt/Source, QuotaFreshnessAt/Source, and
	// ModelDiscoveryFreshnessAt/Source expose the freshness state that fed the
	// candidate's routing evidence.
	HealthFreshnessAt             time.Time
	HealthFreshnessSource         string
	QuotaFreshnessAt              time.Time
	QuotaFreshnessSource          string
	ModelDiscoveryFreshnessAt     time.Time
	ModelDiscoveryFreshnessSource string
	// Components carries the raw score inputs plus the SD-005 score-evidence
	// breakdown used to explain the final Score without parsing Reason.
	Components RouteCandidateComponents
	// Utilization carries the normalized load sample used by the router.
	Utilization RouteUtilizationState
	// LastProbeAt is the time of the most recent aliveness probe for this
	// endpoint. Zero when no probe has been performed.
	LastProbeAt time.Time
	// LastProbeSuccess reports whether the most recent aliveness probe succeeded.
	// Only meaningful when LastProbeAt is non-zero.
	LastProbeSuccess bool
}

// FilterReason* enumerate the canonical disqualification reasons surfaced
// in RouteCandidate.FilterReason and the routing-decision event.
const (
	FilterReasonUnhealthy                   = "unhealthy"
	FilterReasonContextTooSmall             = "context_too_small"
	FilterReasonNoToolSupport               = "no_tool_support"
	FilterReasonReasoningUnsupported        = "reasoning_unsupported"
	FilterReasonScoredBelowTop              = "scored_below_top"
	FilterReasonProviderExcludedFromDefault = "provider_excluded_from_default_routing"
	FilterReasonMeteredOptInRequired        = "metered_opt_in_required"
	// FilterReasonEndpointUnreachable is set when a proactive aliveness probe
	// recorded the provider's endpoint as unreachable within HealthSignalTTL
	// and at least one alternate candidate is available.
	FilterReasonEndpointUnreachable = "endpoint_unreachable"
)

// RouteCandidateComponents breaks down the inputs that fed a candidate's
// final Score so consumers can explain rankings without parsing the
// free-form Reason. Zero fields mean "unknown / not contributing".
type RouteCandidateComponents struct {
	// Power is the catalog model power used by automatic routing. Zero means
	// unknown or not contributing.
	Power int
	// Cost is the per-1k-token cost expressed as a numeric component (USD).
	// Mirrors RouteCandidate.CostUSDPer1kTokens; surfaced here so the event
	// payload carries a single component bundle.
	Cost float64
	// CostClass is the candidate cost class used by the router.
	CostClass string
	// LatencyMS is the observed median latency for this candidate, in
	// milliseconds. Zero when no observations are available.
	LatencyMS float64
	// SpeedTPS is the observed output speed in tokens per second. Zero when
	// no observations are available.
	SpeedTPS float64
	// Utilization is the normalized load signal used to bias ranking. Zero
	// means unknown or not contributing.
	Utilization float64
	// SuccessRate is the observed success rate (0–1) for this candidate.
	// Negative means insufficient data; zero means unknown.
	SuccessRate float64
	// QuotaOK/QuotaPercentUsed/QuotaTrend are subscription quota inputs used
	// by routing. They are zero values for non-subscription candidates.
	QuotaOK          bool
	QuotaPercentUsed int
	QuotaTrend       string
	// Capability is a coarse capability score derived from the candidate's
	// cost class / surface (higher = more capable).
	Capability float64
	// ContextHeadroom is the remaining context after subtracting the request's
	// minimum required prompt window. Zero means unknown or no spare room.
	ContextHeadroom int
